   137→/// Generate CA + server certificates. Returns (ca_cert, ca_key, server_cert, server_key) PEM strings.
   138→fn generate_all() -> Result<(String, String, String, String)> {
   139→    let now = OffsetDateTime::now_utc();
   140→
   141→    // --- CA ---
   142→    let ca_key = KeyPair::generate()?;
   143→    let mut ca_params = CertificateParams::new(Vec::<String>::new())?;
   144→    ca_params
   145→        .distinguished_name
   146→        .push(DnType::CommonName, "Moltis Local CA");
   147→    ca_params
   148→        .distinguished_name
   149→        .push(DnType::OrganizationName, "Moltis");
   150→    ca_params.is_ca = IsCa::Ca(BasicConstraints::Unconstrained);
   151→    ca_params.key_usages = vec![KeyUsagePurpose::KeyCertSign, KeyUsagePurpose::CrlSign];
   152→    // 10-year validity from today.
   153→    ca_params.not_before = now;
   154→    ca_params.not_after = now + time::Duration::days(365 * 10);
   155→    let ca_cert = ca_params.self_signed(&ca_key)?;
   156→
   157→    // --- Server cert signed by CA ---
   158→    let server_key = KeyPair::generate()?;
   159→    let mut server_params = CertificateParams::new(vec![LOCALHOST_DOMAIN.to_string()])?;
   160→    server_params
   161→        .distinguished_name
   162→        .push(DnType::CommonName, LOCALHOST_DOMAIN);
   163→    server_params.subject_alt_names = vec![
   164→        SanType::DnsName(LOCALHOST_DOMAIN.try_into()?),
   165→        SanType::DnsName(format!("*.{LOCALHOST_DOMAIN}").as_str().try_into()?),
   166→        SanType::DnsName("localhost".try_into()?),
   167→        SanType::IpAddress(std::net::IpAddr::V4(std::net::Ipv4Addr::LOCALHOST)),
   168→        SanType::IpAddress(std::net::IpAddr::V6(std::net::Ipv6Addr::LOCALHOST)),
   169→    ];
   170→    // 1-year validity from today.
   171→    server_params.not_before = now;
   172→    server_params.not_after = now + time::Duration::days(365);
   173→    let server_cert = server_params.signed_by(&server_key, &ca_cert, &ca_key)?;
   174→
   175→    Ok((
   176→        ca_cert.pem(),
   177→        ca_key.serialize_pem(),
   178→        server_cert.pem(),
   179→        server_key.serialize_pem(),
   180→    ))
   181→}
