   183→/// Load cert + key PEM files into a `rustls::ServerConfig`.
   184→fn load_rustls_config(cert_path: &Path, key_path: &Path) -> Result<ServerConfig> {
   185→    // Ensure a crypto provider is installed (ring via feature flag).
   186→    let _ = rustls::crypto::ring::default_provider().install_default();
   187→    let cert_file = std::fs::File::open(cert_path).context("open server cert")?;
   188→    let key_file = std::fs::File::open(key_path).context("open server key")?;
   189→
   190→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(cert_file))
   191→        .collect::<std::result::Result<Vec<_>, _>>()
   192→        .context("parse certs")?;
   193→
   194→    let key = rustls_pemfile::private_key(&mut BufReader::new(key_file))
   195→        .context("parse private key")?
   196→        .context("no private key found")?;
   197→
   198→    let mut config = ServerConfig::builder()
   199→        .with_no_client_auth()
   200→        .with_single_cert(certs, key)
   201→        .context("build rustls ServerConfig")?;
   202→    config.alpn_protocols = vec![b"h2".to_vec(), b"http/1.1".to_vec()];
   203→    Ok(config)
   204→}
