   236→/// Start a plain-HTTP server that serves the CA cert and redirects to HTTPS.
   237→pub async fn start_http_redirect_server(
   238→    bind: &str,
   239→    http_port: u16,
   240→    https_port: u16,
   241→    ca_cert_path: &Path,
   242→) -> Result<()> {
   243→    let ca_pem = std::fs::read(ca_cert_path).context("read CA cert")?;
   244→    let localhost_mode = is_localhost_name(bind);
   245→    let state = HttpRedirectState {
   246→        https_port,
   247→        ca_pem: Arc::new(ca_pem),
   248→        localhost_mode,
   249→        bind_host: bind.to_string(),
   250→    };
   251→
   252→    let app = Router::new()
   253→        .route("/certs/ca.pem", get(serve_ca_cert))
   254→        .fallback(redirect_to_https)
   255→        .with_state(state);
   256→
   257→    let addr: SocketAddr = format!("{bind}:{http_port}").parse()?;
   258→    let listener = tokio::net::TcpListener::bind(addr).await?;
   259→    let display_host = if localhost_mode {
   260→        "localhost"
   261→    } else {
   262→        bind
   263→    };
   264→    info!(
   265→        "HTTP redirect server listening http://{}:{http_port}/certs/ca.pem",
   266→        display_host
   267→    );
   268→    axum::serve(listener, app).await?;
   269→    Ok(())
   270→}
