   272→async fn serve_ca_cert(State(state): State<HttpRedirectState>) -> impl IntoResponse {
   273→    (
   274→        [
   275→            ("content-type", "application/x-pem-file"),
   276→            (
   277→                "content-disposition",
   278→                "attachment; filename=\"moltis-ca.pem\"",
   279→            ),
