   285→async fn redirect_to_https(
   286→    State(state): State<HttpRedirectState>,
   287→    headers: axum::http::HeaderMap,
   288→    uri: axum::http::Uri,
   289→) -> impl IntoResponse {
   290→    let host = if state.localhost_mode {
