    66→impl CertManager for FsCertManager {
    67→    fn ensure_certs(&self) -> Result<(PathBuf, PathBuf, PathBuf)> {
    68→        let ca_cert_path = self.cert_dir.join("ca.pem");
    69→        let ca_key_path = self.cert_dir.join("ca-key.pem");
    70→        let server_cert_path = self.cert_dir.join("server.pem");
    71→        let server_key_path = self.cert_dir.join("server-key.pem");
    72→
    73→        let need_regen = !ca_cert_path.exists()
    74→            || !server_cert_path.exists()
    75→            || !server_key_path.exists()
    76→            || is_expired(&server_cert_path, 30);
    77→
    78→        if need_regen {
    79→            info!("generating TLS certificates");
    80→            let (ca_cert_pem, ca_key_pem, server_cert_pem, server_key_pem) = generate_all()?;
    81→            std::fs::write(&ca_cert_path, &ca_cert_pem)?;
    82→            std::fs::write(&ca_key_path, &ca_key_pem)?;
    83→            std::fs::write(&server_cert_path, &server_cert_pem)?;
    84→            std::fs::write(&server_key_path, &server_key_pem)?;
    85→            info!(dir = %self.cert_dir.display(), "certificates written");
    86→        }
    87→
    88→        Ok((ca_cert_path, server_cert_path, server_key_path))
    89→    }
