    96→/// Check if a PEM cert file needs regeneration.
    97→///
    98→/// Returns `true` when the file is older than `days` days (proxy for
    99→/// approaching expiry) **or** when it was generated before the
   100→/// `moltis.localhost` SAN was added. The DER-encoded cert contains
   101→/// DNS names as raw ASCII (IA5String), so a byte search on the decoded
   102→/// DER is sufficient to detect the missing SAN.
   103→fn is_expired(path: &Path, days: u64) -> bool {
   104→    let Ok(meta) = std::fs::metadata(path) else {
   105→        return true;
   106→    };
   107→    let Ok(modified) = meta.modified() else {
   108→        return true;
   109→    };
   110→    let age = SystemTime::now()
   111→        .duration_since(modified)
   112→        .unwrap_or_default();
   113→    if age > time::Duration::days(days as i64).unsigned_abs() {
   114→        return true;
   115→    }
   116→    // Regenerate if the cert predates the moltis.localhost SAN migration.
   117→    needs_san_update(path)
   118→}
   119→
   120→/// Returns `true` if the cert at `path` does not contain the
   121→/// `moltis.localhost` SAN (i.e. was generated before the migration).
   122→fn needs_san_update(path: &Path) -> bool {
   123→    let Ok(pem_bytes) = std::fs::read(path) else {
   124→        return true;
   125→    };
   126→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(pem_bytes.as_slice()))
   127→        .filter_map(|r| r.ok())
   128→        .collect();
   129→    if certs.is_empty() {
   130→        return true;
   131→    }
   132→    let der = certs[0].as_ref();
   133→    !der.windows(LOCALHOST_DOMAIN.len())
   134→        .any(|w| w == LOCALHOST_DOMAIN.as_bytes())
   135→}
